-- Valorize Platform - Improved Database Schema
-- Analysis and improvements based on clean architecture principles

-- ============================================================================
-- CORE TABLES
-- ============================================================================

CREATE TABLE "user" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "name" varchar(200) NOT NULL,
  "avatar" varchar(400),
  "email" varchar(200) NOT NULL UNIQUE,
  "password" text NOT NULL, -- Store hashed passwords
  "coins_to_donate" int NOT NULL DEFAULT 0 CHECK (coins_to_donate >= 0),
  "coins_to_spend" int NOT NULL DEFAULT 0 CHECK (coins_to_spend >= 0),
  "active" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  "updated_at" timestamptz NOT NULL DEFAULT NOW()
);

CREATE TABLE "address" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "id_user" int NOT NULL,
  "nickname" varchar(100) NOT NULL,
  "default_address" boolean NOT NULL DEFAULT false,
  "active" boolean NOT NULL DEFAULT true,
  "cpf" varchar(20), -- Brazilian tax ID - optional for international users
  "zip_code" varchar(15) NOT NULL, -- Increased for international postal codes
  "street" varchar(200) NOT NULL, -- Increased length for international addresses
  "number" varchar(20), -- Changed to varchar for addresses like "123A"
  "city" varchar(100) NOT NULL, -- Increased for international cities
  "neighborhood" varchar(100),
  "complement" varchar(100),
  "state" varchar(50) NOT NULL, -- Increased for international states/provinces
  "country" varchar(2) NOT NULL DEFAULT 'BR', -- ISO country code
  "reference" varchar(200),
  "created_at" timestamptz NOT NULL DEFAULT NOW()
);

-- ============================================================================
-- GAMIFICATION TABLES
-- ============================================================================

CREATE TABLE "initiatives" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "title" varchar(200) NOT NULL,
  "description" text NOT NULL,
  "image" varchar(500), -- Increased for URLs
  "coins" int NOT NULL CHECK (coins > 0),
  "active" boolean NOT NULL DEFAULT true,
  "visible" boolean NOT NULL DEFAULT true,
  "rules" jsonb, -- Changed to jsonb for better performance
  "tags" jsonb, -- Changed to jsonb for better performance
  "link" varchar(500), -- Increased for full URLs
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  "updated_at" timestamptz NOT NULL DEFAULT NOW()
);

CREATE TABLE "credits" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "date" timestamptz NOT NULL DEFAULT NOW(),
  "id_user" int NOT NULL,
  "id_initiative" int NOT NULL,
  "quantity" int NOT NULL CHECK (quantity > 0),
  "created_at" timestamptz NOT NULL DEFAULT NOW()
);

CREATE TABLE "compliment" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "date" timestamptz NOT NULL DEFAULT NOW(),
  "id_sender_user" int NOT NULL,
  "id_receiver_user" int NOT NULL,
  "quantity" int NOT NULL CHECK (quantity > 0),
  "company_value" varchar(100) NOT NULL,
  "description" varchar(1000) NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT NOW()
);

-- ============================================================================
-- REWARDS SYSTEM
-- ============================================================================

CREATE TABLE "rewards" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "title" varchar(200) NOT NULL,
  "image" varchar(500),
  "description" text NOT NULL,
  "price" decimal(10,2) NOT NULL CHECK (price > 0), -- Better for monetary values
  "active" boolean NOT NULL DEFAULT true,
  "category" varchar(100) NOT NULL,
  "brand" varchar(100),
  "redeemed" int NOT NULL DEFAULT 0 CHECK (redeemed >= 0),
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  "updated_at" timestamptz NOT NULL DEFAULT NOW(),
  "limited" boolean NOT NULL DEFAULT false,
  "slug" varchar(100) NOT NULL UNIQUE -- Increased length for SEO-friendly URLs
);

CREATE TABLE "stock" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "id_reward" int NOT NULL, -- Fixed naming consistency
  "characteristic" varchar(100) NOT NULL, -- Size, color, etc.
  "quantity" int NOT NULL CHECK (quantity >= 0) -- Changed from smallint for scalability
);

CREATE TABLE "redeem" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "date" timestamptz NOT NULL DEFAULT NOW(),
  "id_user" int NOT NULL,
  "id_reward" int NOT NULL,
  "id_address" int, -- Optional - some rewards might not require shipping
  "purchased" boolean NOT NULL DEFAULT false,
  "delivery_estimate" date,
  "cancelled" boolean NOT NULL DEFAULT false,
  "received_date" date,
  "cost" decimal(10,2) NOT NULL CHECK (cost >= 0), -- Better precision
  "carrier" varchar(100),
  "tracking_code" varchar(100),
  "observations" text, -- Increased length for detailed notes
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  "updated_at" timestamptz NOT NULL DEFAULT NOW()
);

-- ============================================================================
-- FAQ SYSTEM
-- ============================================================================

CREATE TABLE "doubts" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "question" varchar(500) NOT NULL, -- Increased length
  "answer" text NOT NULL,
  "tags" jsonb, -- Better performance than json
  "active" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  "updated_at" timestamptz NOT NULL DEFAULT NOW()
);

-- ============================================================================
-- ADMIN SYSTEM (RBAC)
-- ============================================================================

CREATE TABLE "admin_roles" (
  "name" varchar(50) PRIMARY KEY,
  "description" varchar(200) NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT NOW()
);

CREATE TABLE "admin_permissions" (
  "name" varchar(50) PRIMARY KEY,
  "description" varchar(200) NOT NULL, -- Added description for clarity
  "created_at" timestamptz NOT NULL DEFAULT NOW()
);

CREATE TABLE "permissions_to_roles" (
  "role_name" varchar(50) NOT NULL,
  "permission_name" varchar(50) NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  PRIMARY KEY ("role_name", "permission_name")
);

CREATE TABLE "admin_users" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, -- Removed UNIQUE (redundant)
  "email" varchar(200) NOT NULL UNIQUE, -- Increased length, added unique
  "avatar" varchar(500),
  "name" varchar(100) NOT NULL, -- Increased length
  "role" varchar(50) NOT NULL,
  "active" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  "updated_at" timestamptz NOT NULL DEFAULT NOW()
);

-- ============================================================================
-- FOREIGN KEY CONSTRAINTS
-- ============================================================================

ALTER TABLE "address" ADD FOREIGN KEY ("id_user") REFERENCES "user" ("id") ON DELETE CASCADE;

ALTER TABLE "credits" ADD FOREIGN KEY ("id_user") REFERENCES "user" ("id") ON DELETE CASCADE;
ALTER TABLE "credits" ADD FOREIGN KEY ("id_initiative") REFERENCES "initiatives" ("id") ON DELETE RESTRICT;

ALTER TABLE "compliment" ADD FOREIGN KEY ("id_sender_user") REFERENCES "user" ("id") ON DELETE CASCADE;
ALTER TABLE "compliment" ADD FOREIGN KEY ("id_receiver_user") REFERENCES "user" ("id") ON DELETE CASCADE;

ALTER TABLE "stock" ADD FOREIGN KEY ("id_reward") REFERENCES "rewards" ("id") ON DELETE CASCADE;

ALTER TABLE "redeem" ADD FOREIGN KEY ("id_user") REFERENCES "user" ("id") ON DELETE CASCADE;
ALTER TABLE "redeem" ADD FOREIGN KEY ("id_reward") REFERENCES "rewards" ("id") ON DELETE RESTRICT;
ALTER TABLE "redeem" ADD FOREIGN KEY ("id_address") REFERENCES "address" ("id") ON DELETE SET NULL;

ALTER TABLE "admin_users" ADD FOREIGN KEY ("role") REFERENCES "admin_roles" ("name") ON DELETE RESTRICT;

ALTER TABLE "permissions_to_roles" ADD FOREIGN KEY ("role_name") REFERENCES "admin_roles" ("name") ON DELETE CASCADE;
ALTER TABLE "permissions_to_roles" ADD FOREIGN KEY ("permission_name") REFERENCES "admin_permissions" ("name") ON DELETE CASCADE;

-- ============================================================================
-- CONSTRAINTS & BUSINESS RULES
-- ============================================================================

-- Prevent self-compliments
ALTER TABLE "compliment" ADD CONSTRAINT "no_self_compliment" 
  CHECK ("id_sender_user" != "id_receiver_user");

-- Only one default address per user
CREATE UNIQUE INDEX "idx_user_default_address" ON "address" ("id_user") 
  WHERE "default_address" = true AND "active" = true;

-- ============================================================================
-- INDEXES FOR PERFORMANCE
-- ============================================================================

-- User queries
CREATE INDEX "idx_user_email" ON "user" ("email");
CREATE INDEX "idx_user_active" ON "user" ("active");

-- Address queries
CREATE INDEX "idx_address_user" ON "address" ("id_user");
CREATE INDEX "idx_address_active" ON "address" ("active");

-- Credits tracking
CREATE INDEX "idx_credits_user" ON "credits" ("id_user");
CREATE INDEX "idx_credits_date" ON "credits" ("date");
CREATE INDEX "idx_credits_initiative" ON "credits" ("id_initiative");

-- Compliments
CREATE INDEX "idx_compliment_receiver" ON "compliment" ("id_receiver_user");
CREATE INDEX "idx_compliment_sender" ON "compliment" ("id_sender_user");
CREATE INDEX "idx_compliment_date" ON "compliment" ("date");

-- Rewards
CREATE INDEX "idx_rewards_active" ON "rewards" ("active");
CREATE INDEX "idx_rewards_category" ON "rewards" ("category");
CREATE INDEX "idx_rewards_price" ON "rewards" ("price");

-- Redemptions
CREATE INDEX "idx_redeem_user" ON "redeem" ("id_user");
CREATE INDEX "idx_redeem_date" ON "redeem" ("date");
CREATE INDEX "idx_redeem_status" ON "redeem" ("cancelled", "purchased");

-- Full-text search indexes
CREATE INDEX "idx_rewards_search" ON "rewards" USING gin(to_tsvector('english', title || ' ' || description));
CREATE INDEX "idx_initiatives_search" ON "initiatives" USING gin(to_tsvector('english', title || ' ' || description));

-- JSON indexes for better performance
CREATE INDEX "idx_initiatives_tags" ON "initiatives" USING gin("tags");
CREATE INDEX "idx_doubts_tags" ON "doubts" USING gin("tags");

-- ============================================================================
-- TRIGGERS FOR AUDIT TRAIL
-- ============================================================================

-- Function to update updated_at timestamp
CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$ language 'plpgsql';

-- Apply to relevant tables
CREATE TRIGGER update_user_updated_at BEFORE UPDATE ON "user" 
  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

CREATE TRIGGER update_initiatives_updated_at BEFORE UPDATE ON "initiatives" 
  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

CREATE TRIGGER update_rewards_updated_at BEFORE UPDATE ON "rewards" 
  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

CREATE TRIGGER update_redeem_updated_at BEFORE UPDATE ON "redeem" 
  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

CREATE TRIGGER update_doubts_updated_at BEFORE UPDATE ON "doubts" 
  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

CREATE TRIGGER update_admin_users_updated_at BEFORE UPDATE ON "admin_users" 
  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

-- ============================================================================
-- SECURITY & COMPLIANCE ENHANCEMENTS
-- ============================================================================

-- User security and compliance tracking
CREATE TABLE "user_security" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "id_user" int NOT NULL,
  "password_hash" text NOT NULL, -- bcrypt hash with high salt rounds
  "password_changed_at" timestamptz NOT NULL DEFAULT NOW(),
  "failed_login_attempts" int NOT NULL DEFAULT 0,
  "locked_until" timestamptz,
  "last_login_at" timestamptz,
  "last_login_ip" inet,
  "mfa_enabled" boolean NOT NULL DEFAULT false,
  "mfa_secret" text, -- Encrypted TOTP secret
  "backup_codes" text[], -- Encrypted backup codes
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  "updated_at" timestamptz NOT NULL DEFAULT NOW()
);

-- Rate limiting for security
CREATE TABLE "rate_limits" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "user_id" int,
  "ip_address" inet,
  "endpoint" varchar(100) NOT NULL,
  "attempts" int NOT NULL DEFAULT 1,
  "window_start" timestamptz NOT NULL DEFAULT NOW(),
  "blocked_until" timestamptz,
  "created_at" timestamptz NOT NULL DEFAULT NOW()
);

-- Audit logs for compliance (GDPR/SOX)
CREATE TABLE "audit_logs" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "user_id" int,
  "action" varchar(50) NOT NULL, -- CREATE, UPDATE, DELETE, LOGIN, etc.
  "table_name" varchar(50),
  "record_id" varchar(50),
  "old_values" jsonb,
  "new_values" jsonb,
  "ip_address" inet,
  "user_agent" text,
  "timestamp" timestamptz NOT NULL DEFAULT NOW(),
  "session_id" varchar(255)
);

-- GDPR compliance - data processing consent
CREATE TABLE "user_consents" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "user_id" int NOT NULL,
  "consent_type" varchar(50) NOT NULL, -- MARKETING, ANALYTICS, COOKIES, etc.
  "granted" boolean NOT NULL,
  "ip_address" inet,
  "user_agent" text,
  "granted_at" timestamptz NOT NULL DEFAULT NOW(),
  "withdrawn_at" timestamptz,
  "version" varchar(10) NOT NULL DEFAULT '1.0' -- Privacy policy version
);

-- Encrypted sensitive data storage
CREATE TABLE "encrypted_personal_data" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "user_id" int NOT NULL,
  "data_type" varchar(50) NOT NULL, -- CPF, PHONE, etc.
  "encrypted_value" text NOT NULL, -- AES-256 encrypted
  "hash_value" varchar(64), -- SHA-256 hash for search/comparison
  "encryption_key_version" varchar(10) NOT NULL DEFAULT '1.0',
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  "updated_at" timestamptz NOT NULL DEFAULT NOW()
);

-- Session management for security
CREATE TABLE "user_sessions" (
  "id" varchar(255) PRIMARY KEY, -- JWT token ID
  "user_id" int NOT NULL,
  "device_info" jsonb, -- Browser, OS, etc.
  "ip_address" inet,
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  "expires_at" timestamptz NOT NULL,
  "revoked_at" timestamptz,
  "last_activity" timestamptz NOT NULL DEFAULT NOW()
);

-- ============================================================================
-- INTERNATIONALIZATION & LOCALIZATION
-- ============================================================================

-- Supported languages and locales
CREATE TABLE "languages" (
  "code" varchar(5) PRIMARY KEY, -- ISO 639-1 + optional country (e.g., 'en', 'pt-BR')
  "name" varchar(100) NOT NULL,
  "native_name" varchar(100) NOT NULL,
  "active" boolean NOT NULL DEFAULT true,
  "rtl" boolean NOT NULL DEFAULT false, -- Right-to-left languages
  "created_at" timestamptz NOT NULL DEFAULT NOW()
);

-- User language preferences
CREATE TABLE "user_preferences" (
  "user_id" int PRIMARY KEY,
  "language_code" varchar(5) NOT NULL DEFAULT 'en',
  "timezone" varchar(50) NOT NULL DEFAULT 'UTC', -- IANA timezone
  "currency_code" varchar(3) NOT NULL DEFAULT 'USD', -- ISO 4217
  "date_format" varchar(20) NOT NULL DEFAULT 'YYYY-MM-DD',
  "time_format" varchar(10) NOT NULL DEFAULT '24h', -- 24h or 12h
  "number_format" varchar(10) NOT NULL DEFAULT 'en-US', -- Locale for numbers
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  "updated_at" timestamptz NOT NULL DEFAULT NOW()
);

-- Multi-language content for initiatives
CREATE TABLE "initiatives_i18n" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "initiative_id" int NOT NULL,
  "language_code" varchar(5) NOT NULL,
  "title" varchar(200) NOT NULL,
  "description" text NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  "updated_at" timestamptz NOT NULL DEFAULT NOW(),
  UNIQUE("initiative_id", "language_code")
);

-- Multi-language content for rewards
CREATE TABLE "rewards_i18n" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "reward_id" int NOT NULL,
  "language_code" varchar(5) NOT NULL,
  "title" varchar(200) NOT NULL,
  "description" text NOT NULL,
  "category" varchar(100) NOT NULL,
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  "updated_at" timestamptz NOT NULL DEFAULT NOW(),
  UNIQUE("reward_id", "language_code")
);

-- Multi-language content for company values
CREATE TABLE "company_values" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "code" varchar(50) NOT NULL UNIQUE, -- Internal code (e.g., 'INNOVATION')
  "active" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  "updated_at" timestamptz NOT NULL DEFAULT NOW()
);

CREATE TABLE "company_values_i18n" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "value_id" int NOT NULL,
  "language_code" varchar(5) NOT NULL,
  "name" varchar(100) NOT NULL,
  "description" text,
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  UNIQUE("value_id", "language_code")
);

-- Multi-currency support for rewards pricing
CREATE TABLE "currencies" (
  "code" varchar(3) PRIMARY KEY, -- ISO 4217 (USD, EUR, BRL, etc.)
  "name" varchar(100) NOT NULL,
  "symbol" varchar(5) NOT NULL,
  "decimal_places" smallint NOT NULL DEFAULT 2,
  "active" boolean NOT NULL DEFAULT true
);

CREATE TABLE "reward_pricing" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "reward_id" int NOT NULL,
  "currency_code" varchar(3) NOT NULL,
  "price" decimal(15,4) NOT NULL, -- Support for different decimal places
  "coins_price" int NOT NULL, -- Price in platform coins
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  "updated_at" timestamptz NOT NULL DEFAULT NOW(),
  UNIQUE("reward_id", "currency_code")
);

-- ============================================================================
-- SOFT DELETES & DATA RETENTION
-- ============================================================================

-- Add soft delete columns to existing tables
ALTER TABLE "user" ADD COLUMN "deleted_at" timestamptz;
ALTER TABLE "initiatives" ADD COLUMN "deleted_at" timestamptz;
ALTER TABLE "rewards" ADD COLUMN "deleted_at" timestamptz;
ALTER TABLE "address" ADD COLUMN "deleted_at" timestamptz;

-- Data retention policy tracking
CREATE TABLE "data_retention_policies" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "table_name" varchar(50) NOT NULL,
  "retention_days" int NOT NULL,
  "deletion_strategy" varchar(20) NOT NULL, -- SOFT, HARD, ARCHIVE
  "last_cleanup" timestamptz,
  "created_at" timestamptz NOT NULL DEFAULT NOW()
);

-- ============================================================================
-- BUSINESS INTELLIGENCE & ANALYTICS
-- ============================================================================

-- User activity tracking for analytics
CREATE TABLE "user_activities" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "user_id" int NOT NULL,
  "activity_type" varchar(50) NOT NULL, -- LOGIN, PRAISE_SENT, REWARD_CLAIMED, etc.
  "metadata" jsonb, -- Additional activity data
  "ip_address" inet,
  "user_agent" text,
  "timestamp" timestamptz NOT NULL DEFAULT NOW()
);

-- Company performance metrics
CREATE TABLE "company_metrics" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "metric_name" varchar(100) NOT NULL,
  "metric_value" decimal(15,2) NOT NULL,
  "metric_date" date NOT NULL,
  "department" varchar(100),
  "metadata" jsonb,
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  UNIQUE("metric_name", "metric_date", "department")
);

-- Weekly/Monthly aggregations for performance
CREATE TABLE "praise_statistics" (
  "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "user_id" int NOT NULL,
  "period_type" varchar(10) NOT NULL, -- WEEKLY, MONTHLY, YEARLY
  "period_start" date NOT NULL,
  "praises_sent" int NOT NULL DEFAULT 0,
  "praises_received" int NOT NULL DEFAULT 0,
  "coins_given" int NOT NULL DEFAULT 0,
  "coins_received" int NOT NULL DEFAULT 0,
  "created_at" timestamptz NOT NULL DEFAULT NOW(),
  UNIQUE("user_id", "period_type", "period_start")
);

-- ============================================================================
-- ADDITIONAL FOREIGN KEY CONSTRAINTS
-- ============================================================================

ALTER TABLE "user_security" ADD FOREIGN KEY ("id_user") REFERENCES "user" ("id") ON DELETE CASCADE;
ALTER TABLE "user_consents" ADD FOREIGN KEY ("user_id") REFERENCES "user" ("id") ON DELETE CASCADE;
ALTER TABLE "encrypted_personal_data" ADD FOREIGN KEY ("user_id") REFERENCES "user" ("id") ON DELETE CASCADE;
ALTER TABLE "user_sessions" ADD FOREIGN KEY ("user_id") REFERENCES "user" ("id") ON DELETE CASCADE;
ALTER TABLE "user_preferences" ADD FOREIGN KEY ("user_id") REFERENCES "user" ("id") ON DELETE CASCADE;
ALTER TABLE "user_preferences" ADD FOREIGN KEY ("language_code") REFERENCES "languages" ("code");
ALTER TABLE "initiatives_i18n" ADD FOREIGN KEY ("initiative_id") REFERENCES "initiatives" ("id") ON DELETE CASCADE;
ALTER TABLE "initiatives_i18n" ADD FOREIGN KEY ("language_code") REFERENCES "languages" ("code");
ALTER TABLE "rewards_i18n" ADD FOREIGN KEY ("reward_id") REFERENCES "rewards" ("id") ON DELETE CASCADE;
ALTER TABLE "rewards_i18n" ADD FOREIGN KEY ("language_code") REFERENCES "languages" ("code");
ALTER TABLE "company_values_i18n" ADD FOREIGN KEY ("value_id") REFERENCES "company_values" ("id") ON DELETE CASCADE;
ALTER TABLE "company_values_i18n" ADD FOREIGN KEY ("language_code") REFERENCES "languages" ("code");
ALTER TABLE "reward_pricing" ADD FOREIGN KEY ("reward_id") REFERENCES "rewards" ("id") ON DELETE CASCADE;
ALTER TABLE "reward_pricing" ADD FOREIGN KEY ("currency_code") REFERENCES "currencies" ("code");
ALTER TABLE "user_activities" ADD FOREIGN KEY ("user_id") REFERENCES "user" ("id") ON DELETE CASCADE;
ALTER TABLE "praise_statistics" ADD FOREIGN KEY ("user_id") REFERENCES "user" ("id") ON DELETE CASCADE;

-- Link compliments to company values
ALTER TABLE "compliment" ADD COLUMN "company_value_id" int;
ALTER TABLE "compliment" ADD FOREIGN KEY ("company_value_id") REFERENCES "company_values" ("id");

-- ============================================================================
-- ADDITIONAL CONSTRAINTS & BUSINESS RULES
-- ============================================================================

-- Security constraints
ALTER TABLE "user_security" ADD CONSTRAINT "check_failed_attempts" 
  CHECK ("failed_login_attempts" >= 0 AND "failed_login_attempts" <= 10);

ALTER TABLE "rate_limits" ADD CONSTRAINT "check_attempts_positive" 
  CHECK ("attempts" > 0);

-- Internationalization constraints
ALTER TABLE "user_preferences" ADD CONSTRAINT "check_valid_time_format" 
  CHECK ("time_format" IN ('12h', '24h'));

-- Business logic constraints
ALTER TABLE "praise_statistics" ADD CONSTRAINT "check_positive_stats"
  CHECK ("praises_sent" >= 0 AND "praises_received" >= 0 AND "coins_given" >= 0 AND "coins_received" >= 0);

ALTER TABLE "reward_pricing" ADD CONSTRAINT "check_positive_prices"
  CHECK ("price" > 0 AND "coins_price" > 0);

-- ============================================================================
-- ADDITIONAL INDEXES FOR SECURITY & PERFORMANCE
-- ============================================================================

-- Security indexes
CREATE INDEX "idx_user_security_user" ON "user_security" ("id_user");
CREATE INDEX "idx_user_security_login_attempts" ON "user_security" ("failed_login_attempts", "locked_until");
CREATE INDEX "idx_rate_limits_user_endpoint" ON "rate_limits" ("user_id", "endpoint", "window_start");
CREATE INDEX "idx_rate_limits_ip_endpoint" ON "rate_limits" ("ip_address", "endpoint", "window_start");
CREATE INDEX "idx_audit_logs_user_action" ON "audit_logs" ("user_id", "action", "timestamp");
CREATE INDEX "idx_audit_logs_table_record" ON "audit_logs" ("table_name", "record_id");
CREATE INDEX "idx_user_sessions_user" ON "user_sessions" ("user_id", "expires_at");
CREATE INDEX "idx_user_sessions_expires" ON "user_sessions" ("expires_at") WHERE "revoked_at" IS NULL;

-- Internationalization indexes
CREATE INDEX "idx_user_preferences_language" ON "user_preferences" ("language_code");
CREATE INDEX "idx_initiatives_i18n_lookup" ON "initiatives_i18n" ("initiative_id", "language_code");
CREATE INDEX "idx_rewards_i18n_lookup" ON "rewards_i18n" ("reward_id", "language_code");
CREATE INDEX "idx_company_values_i18n_lookup" ON "company_values_i18n" ("value_id", "language_code");

-- Analytics indexes
CREATE INDEX "idx_user_activities_user_type" ON "user_activities" ("user_id", "activity_type", "timestamp");
CREATE INDEX "idx_user_activities_timestamp" ON "user_activities" ("timestamp");
CREATE INDEX "idx_praise_stats_period" ON "praise_statistics" ("period_type", "period_start");
CREATE INDEX "idx_company_metrics_date" ON "company_metrics" ("metric_date", "metric_name");

-- Soft delete indexes (partial indexes for better performance)
CREATE INDEX "idx_user_active" ON "user" ("id") WHERE "deleted_at" IS NULL;
CREATE INDEX "idx_initiatives_active" ON "initiatives" ("id") WHERE "deleted_at" IS NULL;
CREATE INDEX "idx_rewards_active_not_deleted" ON "rewards" ("active") WHERE "deleted_at" IS NULL;

-- ============================================================================
-- VIEWS FOR COMMON QUERIES
-- ============================================================================

-- Active users with preferences and security info (without sensitive data)
CREATE VIEW "v_active_users" AS
SELECT 
  u.id,
  u.name,
  u.email,
  u.coins_to_donate,
  u.coins_to_spend,
  u.created_at,
  up.language_code,
  up.timezone,
  up.currency_code,
  us.last_login_at,
  us.mfa_enabled
FROM "user" u
LEFT JOIN "user_preferences" up ON u.id = up.user_id
LEFT JOIN "user_security" us ON u.id = us.id_user
WHERE u.active = true AND u.deleted_at IS NULL;

-- Localized initiatives
CREATE VIEW "v_initiatives_localized" AS
SELECT 
  i.id,
  i.coins,
  i.active,
  i.visible,
  i.rules,
  i.tags,
  i.link,
  i.created_at,
  ii.language_code,
  ii.title,
  ii.description
FROM "initiatives" i
LEFT JOIN "initiatives_i18n" ii ON i.id = ii.initiative_id
WHERE i.deleted_at IS NULL;

-- Localized rewards with pricing
CREATE VIEW "v_rewards_localized" AS
SELECT 
  r.id,
  r.active,
  r.brand,
  r.redeemed,
  r.limited,
  r.slug,
  r.created_at,
  ri.language_code,
  ri.title,
  ri.description,
  ri.category,
  rp.currency_code,
  rp.price,
  rp.coins_price
FROM "rewards" r
LEFT JOIN "rewards_i18n" ri ON r.id = ri.reward_id
LEFT JOIN "reward_pricing" rp ON r.id = rp.reward_id
WHERE r.deleted_at IS NULL;

-- ============================================================================
-- ADDITIONAL TRIGGERS
-- ============================================================================

-- Trigger for audit logging
CREATE OR REPLACE FUNCTION log_data_changes()
RETURNS TRIGGER AS $$
BEGIN
  INSERT INTO "audit_logs" (
    "user_id",
    "action", 
    "table_name",
    "record_id",
    "old_values",
    "new_values",
    "timestamp"
  ) VALUES (
    CASE WHEN TG_OP = 'DELETE' THEN OLD.id ELSE NEW.id END,
    TG_OP,
    TG_TABLE_NAME,
    CASE WHEN TG_OP = 'DELETE' THEN OLD.id::text ELSE NEW.id::text END,
    CASE WHEN TG_OP IN ('UPDATE', 'DELETE') THEN row_to_json(OLD) ELSE NULL END,
    CASE WHEN TG_OP IN ('INSERT', 'UPDATE') THEN row_to_json(NEW) ELSE NULL END,
    NOW()
  );
  
  RETURN CASE WHEN TG_OP = 'DELETE' THEN OLD ELSE NEW END;
END;
$$ LANGUAGE plpgsql;

-- Apply audit triggers to critical tables
CREATE TRIGGER audit_user_changes 
  AFTER INSERT OR UPDATE OR DELETE ON "user"
  FOR EACH ROW EXECUTE FUNCTION log_data_changes();

CREATE TRIGGER audit_compliment_changes 
  AFTER INSERT OR UPDATE OR DELETE ON "compliment"
  FOR EACH ROW EXECUTE FUNCTION log_data_changes();

CREATE TRIGGER audit_redeem_changes 
  AFTER INSERT OR UPDATE OR DELETE ON "redeem"
  FOR EACH ROW EXECUTE FUNCTION log_data_changes();

-- Update triggers for new tables
CREATE TRIGGER update_user_security_updated_at BEFORE UPDATE ON "user_security" 
  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

CREATE TRIGGER update_user_preferences_updated_at BEFORE UPDATE ON "user_preferences" 
  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

CREATE TRIGGER update_initiatives_i18n_updated_at BEFORE UPDATE ON "initiatives_i18n" 
  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

CREATE TRIGGER update_rewards_i18n_updated_at BEFORE UPDATE ON "rewards_i18n" 
  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

CREATE TRIGGER update_reward_pricing_updated_at BEFORE UPDATE ON "reward_pricing" 
  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

